string s = "hello world";
cout << s.substr(0, 5) << endl;  // hello
cout << s.substr(6) << endl;     // world

size_t pos = s.find("world");
if (pos != string::npos) {
    cout << "Found at " << pos << endl;  // Found at 6
}

size_t miss = s.find("xyz");
cout << (miss == string::npos) << endl;  // 1 (true)

