sections.example:
string result = "";
vector<string> words = {"hello", "world", "foo"};
for (int i = 0; i < (int)words.size(); i++) {
    if (i > 0) result += " ";
    result += words[i];
}
cout << result << endl;  // hello world foo

// Building from characters
string reversed = "";
string s = "abc";
for (int i = s.size() - 1; i >= 0; i--) {
    reversed += s[i];
}
cout << reversed << endl;  // cba

exercise.starterCode:
int main() {
    vector<string> words = {"the", "quick", "fox"};
    string joined = "";
    for (int i = 0; i < (int)words.size(); i++) {
        if (i > 0) joined += " ";
        joined += words[];
    }
    cout << joined << endl;

    string s = "abcde";
    string reversed = "";
    for (int i = s.size() - 1; i >= 0; i--) {
        reversed += s[];
    }
    cout << reversed << endl;
    return 0;
}
